mapper.select:
SELECT w.order_id AS orderId, w.cl_order_id AS clOrderId, w.product_id AS productId, w.line_id AS lineId, w.order_qty AS orderQty, w.priority, w.status, w.created_at AS createdAt, w.updated_at AS updatedAt, p.product_name AS productName, p.unit, l.line_name AS lineName, co.client_id AS clientId, cl.client_name AS clientName, co.cl_order_date AS clOrderDate, co.cl_delivery_date AS dueDate, IFNULL(ps.stock_qty, 0) AS stockQty, IFNULL(sr.reserved_qty, 0) AS reservedQty, (IFNULL(ps.stock_qty, 0) - IFNULL(sr.reserved_qty, 0)) AS availableQty, w.order_qty AS requiredQty FROM work_order w LEFT JOIN product p ON w.product_id = p.product_id LEFT JOIN production_line l ON w.line_id = l.line_id LEFT JOIN client_order co ON w.cl_order_id = co.cl_order_id LEFT JOIN client cl ON co.client_id = cl.client_id LEFT JOIN product_stock ps ON w.product_id = ps.product_id LEFT JOIN ( SELECT cl_order_id, product_id, SUM(reserved_qty) AS reserved_qty FROM stock_reservation GROUP BY cl_order_id, product_id ) sr ON w.cl_order_id = sr.cl_order_id AND w.product_id = sr.product_id
w.is_deleted = FALSE
AND ( w.order_id LIKE CONCAT('%', #{keyword}, '%') OR w.cl_order_id LIKE CONCAT('%', #{keyword}, '%') OR p.product_name LIKE CONCAT('%', #{keyword}, '%') OR cl.client_name LIKE CONCAT('%', #{keyword}, '%') )
AND w.status = #{status}
AND DATE(w.created_at) >= #{startDate}
AND DATE(w.created_at) <= #{endDate}
ORDER BY
CASE w.priority WHEN 'EMERGENCY' THEN 1 WHEN 'HIGH' THEN 2 WHEN 'NORMAL' THEN 3 WHEN 'LOW' THEN 4 ELSE 5 END ${sortOrder}
${sortColumn} ${sortOrder}
w.created_at DESC
LIMIT #{pageStart}, #{perPageNum}

SELECT COUNT(*) FROM work_order w LEFT JOIN product p ON w.product_id = p.product_id LEFT JOIN client_order co ON w.cl_order_id = co.cl_order_id LEFT JOIN client cl ON co.client_id = cl.client_id
AND ( w.order_id LIKE CONCAT('%', #{keyword}, '%') OR w.cl_order_id LIKE CONCAT('%', #{keyword}, '%') OR p.product_name LIKE CONCAT('%', #{keyword}, '%') OR cl.client_name LIKE CONCAT('%', #{keyword}, '%') )
AND w.status = #{status}
AND DATE(w.created_at) >= #{startDate}
AND DATE(w.created_at) <= #{endDate}

SELECT COUNT(*) 
FROM work_order 
WHERE status = #{status}
